 61→class PostActionHandler(
 62→    private val dispatcher: Dispatcher,
 63→    private val site: SiteModel,
 64→    private val postStore: PostStore,
 65→    private val postListDialogHelper: PostListDialogHelper,
 66→    private val doesPostHaveUnhandledConflict: (PostModel) -> Boolean,
 67→    private val hasUnhandledAutoSave: (PostModel) -> Boolean,
 68→    private val triggerPostListAction: (PostListAction) -> Unit,
 69→    private val triggerPostUploadAction: (PostUploadAction) -> Unit,
 70→    private val triggerPublishAction: (PostModel) -> Unit,
 71→    private val invalidateList: () -> Unit,
 72→    private val checkNetworkConnection: () -> Boolean,
 73→    private val showSnackbar: (SnackbarMessageHolder) -> Unit,
 74→    private val showToast: (ToastMessageHolder) -> Unit,
 75→    private val triggerPreviewStateUpdate: (PostListRemotePreviewState, PostInfoType) -> Unit,
 76→    private val copyPost: (SiteModel, PostModel, Boolean) -> Unit
 77→) {
 78→    private val criticalPostActionTracker = CriticalPostActionTracker(onStateChanged = {
 79→        invalidateList.invoke()
 80→    })
