121→        PageInfo pageInfo = (PageInfo) intent.getSerializableExtra(ARG_PAGE_INFO);
122→
123→        UpdateCommentsScenario commentsScenario = pageInfo == PageInfo.COMMENTS_SNIPPET_PAGE
124→                ? COMMENT_SNIPPET
125→                : GENERIC;
126→
127→        EventBus.getDefault().post(new ReaderEvents.UpdateCommentsStarted(commentsScenario, blogId, postId));
128→
129→        final int commentsToRequest = pageInfo == PageInfo.COMMENTS_SNIPPET_PAGE
130→                ? ReaderConstants.READER_COMMENTS_TO_REQUEST_FOR_POST_SNIPPET
131→                : ReaderConstants.READER_MAX_COMMENTS_TO_REQUEST;
132→
133→        switch (pageInfo) {
134→            case NEXT_PAGE:
135→                int prevPage = ReaderCommentTable.getLastPageNumberForPost(blogId, postId);
136→                mCurrentPage = prevPage + 1;
137→                break;
138→            case FIRST_PAGE:
139→            case COMMENTS_SNIPPET_PAGE:
140→            default:
141→                mCurrentPage = 1;
142→                break;
143→        }
144→
145→        updateCommentsForPost(blogId, postId, mCurrentPage, commentsToRequest, new UpdateResultListener() {
146→            @Override
147→            public void onUpdateResult(UpdateResult result) {
148→                if (commentId > 0) {
149→                    if (ReaderCommentTable.commentExists(blogId, postId, commentId) || !result.isNewOrChanged()) {
150→                        EventBus.getDefault().post(new ReaderEvents.UpdateCommentsEnded(
151→                                result,
152→                                commentsScenario,
153→                                blogId,
154→                                postId
155→                        ));
156→                        stopSelf();
157→                    } else {
158→                        // Comment not found yet, request the next page
159→                        mCurrentPage++;
160→                        updateCommentsForPost(blogId, postId, mCurrentPage, commentsToRequest, this);
161→                    }
162→                } else {
163→                    EventBus.getDefault().post(new ReaderEvents.UpdateCommentsEnded(
164→                            result,
165→                            commentsScenario,
166→                            blogId,
167→                            postId
168→                    ));
169→                    stopSelf();
170→                }
171→            }
172→        });
173→
174→        return START_NOT_STICKY;
175→    }
176→
177→    private static void updateCommentsForPost(final long blogId,
178→                                              final long postId,
179→                                              final int pageNumber,
180→                                              final int commentsToRequest,
181→                                              final ReaderActions.UpdateResultListener resultListener) {
182→        String path = "sites/" + blogId + "/posts/" + postId + "/replies/"
183→                      + "?number=" + Integer.toString(commentsToRequest)
184→                      + "&meta=likes"
185→                      + "&force=wpcom"
186→                      + "&hierarchical=true"
187→                      + "&order=ASC"
188→                      + "&page=" + pageNumber;
189→
190→        RestRequest.Listener listener = new RestRequest.Listener() {
191→            @Override
192→            public void onResponse(JSONObject jsonObject) {
193→                handleUpdateCommentsResponse(jsonObject, blogId, postId, pageNumber, resultListener);
194→            }
195→        };
196→        RestRequest.ErrorListener errorListener = new RestRequest.ErrorListener() {
197→            @Override
198→            public void onErrorResponse(VolleyError volleyError) {
199→                AppLog.e(AppLog.T.READER, volleyError);
200→                resultListener.onUpdateResult(ReaderActions.UpdateResult.FAILED);
201→            }
202→        };
203→        AppLog.d(AppLog.T.READER, "updating comments");
204→        WordPress.getRestClientUtilsV1_1().get(path, null, null, listener, errorListener);
205→    }
206→
207→    private static void handleUpdateCommentsResponse(final JSONObject jsonObject,
208→                                                     final long blogId,
209→                                                     final long postId,
210→                                                     final int pageNumber,
211→                                                     final ReaderActions.UpdateResultListener resultListener) {
212→        if (jsonObject == null) {
213→            resultListener.onUpdateResult(ReaderActions.UpdateResult.FAILED);
214→            return;
215→        }
216→
217→        new Thread() {
218→            @Override
219→            public void run() {
220→                final boolean hasNewComments;
221→
222→                ReaderDatabase.getWritableDb().beginTransaction();
223→                try {
224→                    // purge existing comments if this was a request for the first page of comments
225→                    if (pageNumber == 1) {
226→                        ReaderCommentTable.purgeCommentsForPost(blogId, postId);
227→                    }
228→
229→                    ReaderCommentList serverComments = new ReaderCommentList();
230→                    JSONArray jsonCommentList = jsonObject.optJSONArray("comments");
231→                    if (jsonCommentList != null) {
232→                        for (int i = 0; i < jsonCommentList.length(); i++) {
233→                            JSONObject jsonComment = jsonCommentList.optJSONObject(i);
234→
235→                            // extract this comment and add it to the list
236→                            ReaderComment comment = ReaderComment.fromJson(jsonComment, blogId);
237→                            comment.pageNumber = pageNumber;
238→                            serverComments.add(comment);
239→
240→                            // extract and save likes for this comment
241→                            JSONObject jsonLikes = JSONUtils.getJSONChild(jsonComment, "meta/data/likes");
242→                            if (jsonLikes != null) {
243→                                ReaderUserList likingUsers = ReaderUserList.fromJsonLikes(jsonLikes);
244→                                ReaderUserTable.addOrUpdateUsers(likingUsers);
245→                                ReaderLikeTable.setLikesForComment(comment, likingUsers.getUserIds());
246→                            }
247→                        }
248→                    }
249→
250→                    hasNewComments = (serverComments.size() > 0);
251→
252→                    // save to db regardless of whether any are new so changes to likes are stored
253→                    ReaderCommentTable.addOrUpdateComments(serverComments);
254→                    ReaderDatabase.getWritableDb().setTransactionSuccessful();
255→                } finally {
256→                    ReaderDatabase.getWritableDb().endTransaction();
257→                }
258→
259→                ReaderActions.UpdateResult result =
260→                        (hasNewComments ? ReaderActions.UpdateResult.HAS_NEW : ReaderActions.UpdateResult.UNCHANGED);
261→                resultListener.onUpdateResult(result);
262→            }
263→        }.start();
264→    }
265→}
